sql:
SELECT class, COUNT(*) as Total_taxonomy
FROM taxonomy
GROUP BY class;

SELECT AVG(number_of_versions) AS average_version_count
FROM (
  SELECT assembly_id, COUNT(*) AS number_of_versions
  FROM genome_versions
  GROUP BY assembly_id
) AS version_counts;

SELECT assembly_id, metadata_name, metadata_value
FROM genome_assembly_metadata
ORDER BY assembly_id ASC;

SELECT COUNT(DISTINCT superkingdom) 
FROM taxonomy 
WHERE genus = 'Pseudomonas';

SELECT AVG(stat_value) AS average_sequence_length
FROM genome_assembly_stats
WHERE stat_name = 'sequence_length';

SELECT contact_email
FROM submitters
WHERE submitter_id = 100;

SELECT assembly_id, MAX(version_number) AS latest_version
FROM genome_versions
GROUP BY assembly_id;
